import React, { useState } from "react";
import { 
  Card, 
  Typography, 
  Space, 
  Button, 
  Table, 
  Tag, 
  theme,
  Row,
  Col,
  Input,
  message,
  Popconfirm,
  Avatar,
  Tooltip,
  Modal,
  Form,
  Select
} from "antd";
import { 
  UserOutlined,
  SearchOutlined, 
  PlusOutlined,
  DeleteOutlined,
  EditOutlined,
  MailOutlined,
  PhoneOutlined,
  KeyOutlined,
  ExportOutlined,
  TeamOutlined
} from "@ant-design/icons";
import { useI18n } from "@/framework/i18n/hooks";
import { exportToExcel } from "../../../utils/exportExcel";

const { Title, Text } = Typography;

// Mock Data for Members
const initialMembers = [
  { id: "1", name: "홍길동", role: "Admin", dept: "강남 통합관제팀", email: "admin@msafety.com", phone: "010-1234-5678", lastLogin: "2026-04-06 14:00" },
  { id: "2", name: "김철수", role: "Operator", dept: "판교역 현장대응팀", email: "op1@msafety.com", phone: "010-2345-6789", lastLogin: "2026-04-06 09:30" },
  { id: "3", name: "이영희", role: "Manager", dept: "홍대입구역 서비스팀", email: "manager@msafety.com", phone: "010-3456-7890", lastLogin: "2026-04-05 18:00" },
  { id: "4", name: "박민수", role: "Operator", dept: "서울역 안전지원팀", email: "op2@msafety.com", phone: "010-4567-8901", lastLogin: "2026-04-06 15:45" },
];

export default function MemberManagePage() {
  const { token } = theme.useToken();
  const { t } = useI18n(["storageLocker", "platform", "common"]);
  const [searchText, setSearchText] = useState("");
  const [data, setData] = useState(initialMembers);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [editingItem, setEditingItem] = useState<any>(null);
  const [form] = Form.useForm();

  const showModal = (record?: any) => {
    if (record) {
      setEditingItem(record);
      form.setFieldsValue(record);
    } else {
      setEditingItem(null);
      form.resetFields();
    }
    setIsModalOpen(true);
  };

  const handleSave = () => {
    form.validateFields().then(values => {
      if (editingItem) {
        setData(data.map(item => item.id === editingItem.id ? { ...item, ...values } : item));
        message.success(`${t("common:edit")} ${t("storageLocker:dashboard.ctrlSuccess")}`);
      } else {
        const newItem = {
          id: `${Date.now()}`,
          ...values,
          lastLogin: "-"
        };
        setData([newItem, ...data]);
        message.success(`${t("common:add")} ${t("storageLocker:dashboard.ctrlSuccess")}`);
      }
      setIsModalOpen(false);
    });
  };

  const handleDelete = (id: string) => {
    setData(data.filter(item => item.id !== id));
    message.success(t("common:delete_success"));
  };

  const columns = [
    {
      title: t("common:name"),
      dataIndex: "name",
      key: "name",
      render: (text: string, record: any) => (
        <Space>
          <Avatar icon={<UserOutlined />} style={{ backgroundColor: record.role === "Admin" ? token.colorError : token.colorPrimary }} />
          <div>
            <Text strong>{text}</Text>
            <div style={{ fontSize: 12, color: token.colorTextSecondary }}>{record.dept}</div>
          </div>
        </Space>
      ),
    },
    {
      title: t("common:role"),
      dataIndex: "role",
      key: "role",
      render: (role: string) => {
        let color = role === "Admin" ? "volcano" : role === "Manager" ? "green" : "blue";
        return <Tag color={color}>{role.toUpperCase()}</Tag>;
      },
    },
    {
      title: t("common:contact"),
      key: "contact",
      render: (_: any, record: any) => (
        <Space direction="vertical" size={0}>
          <Tooltip title={record.email}><Text style={{ fontSize: 12 }}><MailOutlined style={{ marginRight: 4 }} /> {record.email}</Text></Tooltip>
          <Text style={{ fontSize: 12 }}><PhoneOutlined style={{ marginRight: 4 }} /> {record.phone}</Text>
        </Space>
      ),
    },
    {
      title: t("common:lastLogin"),
      dataIndex: "lastLogin",
      key: "lastLogin",
      render: (text: string) => <Text type="secondary">{text}</Text>,
    },
    {
      title: t("common:action"),
      key: "action",
      render: (_: any, record: any) => (
        <Space size="middle">
          <Button type="link" size="small" icon={<EditOutlined />} onClick={() => showModal(record)}>
            {t("common:edit")}
          </Button>
          <Popconfirm title={t("common:confirm_delete")} onConfirm={() => handleDelete(record.id)}>
            <Button type="link" size="small" danger icon={<DeleteOutlined />}>
              {t("common:delete")}
            </Button>
          </Popconfirm>
          <Tooltip title={t("common:resetPassword")}>
             <Button type="link" size="small" icon={<KeyOutlined />} onClick={() => message.info(t("common:resetPassSuccess"))} />
          </Tooltip>
        </Space>
      ),
    },
  ];

  const filteredData = data.filter(item => 
    item.name.includes(searchText) || item.dept.includes(searchText) || item.role.toLowerCase().includes(searchText.toLowerCase())
  );

  const handleExportXlsx = async () => {
    const success = await exportToExcel(data, "User_Management_List");
    if (success) {
      message.success(`${t("common:exportXlsx")} ${t("storageLocker:dashboard.ctrlSuccess")}`);
    }
  };

  return (
    <div style={{ padding: 24, display: "flex", flexDirection: "column", gap: 24, height: "100%", overflow: "auto" }}>
      {/* Header */}
      <Card bordered={false} bodyStyle={{ padding: "16px 24px" }} style={{ boxShadow: "0 2px 8px rgba(0,0,0,0.05)" }}>
        <Row gutter={[24, 16]} align="middle">
          <Col xs={24} md={8}>
            <Title level={4} style={{ margin: 0 }}>
              <TeamOutlined style={{ marginRight: 8, color: token.colorPrimary }} />
              {t("storageLocker:navigation.manageMember")}
            </Title>
          </Col>
          <Col xs={24} md={16} style={{ textAlign: "right" }}>
            <Space size="middle">
              <Input 
                placeholder={t("common:search")} 
                prefix={<SearchOutlined />} 
                style={{ width: 250 }}
                onChange={e => setSearchText(e.target.value)}
                allowClear
              />
              <Button type="primary" icon={<PlusOutlined />} onClick={() => showModal()}>
                {t("common:add")}
              </Button>
            </Space>
          </Col>
        </Row>
      </Card>

      {/* Main Grid */}
      <Card bordered={false} bodyStyle={{ padding: 0 }} style={{ flex: 1, boxShadow: "0 2px 8px rgba(0,0,0,0.05)" }}>
        <Table 
          columns={columns} 
          dataSource={filteredData} 
          rowKey="id"
          pagination={{ pageSize: 11 }}
          scroll={{ y: "calc(100vh - 400px)" }}
        />
      </Card>

      <div style={{ textAlign: "left", paddingLeft: 8 }}>
        <Space style={{ width: "100%", justifyContent: "space-between" }}>
          <Text type="secondary">
            {t("common:total")}: {filteredData.length} {t("common:unit_person")}
          </Text>
          <Button icon={<ExportOutlined />} onClick={handleExportXlsx}>
            {t("common:exportXlsx")}
          </Button>
        </Space>
      </div>

      {/* User Add/Edit Modal */}
      <Modal
        title={editingItem ? `${t("common:edit")} ${t("storageLocker:navigation.manageMember")}` : `${t("common:add")} ${t("storageLocker:navigation.manageMember")}`}
        open={isModalOpen}
        onOk={handleSave}
        onCancel={() => setIsModalOpen(false)}
        destroyOnClose
      >
        <Form form={form} layout="vertical" style={{ marginTop: 16 }}>
          <Row gutter={16}>
            <Col span={12}>
              <Form.Item name="name" label={t("common:name")} rules={[{ required: true }]}>
                <Input />
              </Form.Item>
            </Col>
            <Col span={12}>
              <Form.Item name="role" label={t("common:role")} rules={[{ required: true }]} initialValue="Operator">
                <Select>
                  <Select.Option value="Admin">Admin</Select.Option>
                  <Select.Option value="Manager">Manager</Select.Option>
                  <Select.Option value="Operator">Operator</Select.Option>
                </Select>
              </Form.Item>
            </Col>
          </Row>

          <Form.Item name="dept" label={t("common:dept")} rules={[{ required: true }]}>
            <Input />
          </Form.Item>

          <Form.Item name="email" label="E-mail" rules={[{ required: true, type: "email" }]}>
            <Input prefix={<MailOutlined />} placeholder="user@example.com" />
          </Form.Item>

          <Form.Item name="phone" label={t("common:contact")} rules={[{ required: true }]}>
            <Input prefix={<PhoneOutlined />} placeholder="010-XXXX-XXXX" />
          </Form.Item>
        </Form>
      </Modal>
    </div>
  );
}
